/* NeoBrutalism skin for ATN/Anton Equipment */
:root {
    --nb-bg: #f8f9fa;
    --nb-ink: #1a1a1a;
    --nb-primary: #dc2626; /* red */
    --nb-accent: #1e40af; /* blue */
    --nb-success: #16a34a;
    --nb-warning: #f59e0b;
    --nb-whatsapp: #25D366;
    --nb-border-width: 4px;
    --nb-radius: 10px;
    --nb-shadow-x: 8px;
    --nb-shadow-y: 8px;
}

/* base */
.nb-container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
}

.nb-section {
    padding: 48px 0;
}

.nb-stroke {
    border: var(--nb-border-width) solid var(--nb-ink);
}

.nb-shadow {
    box-shadow: var(--nb-shadow-x) var(--nb-shadow-y) 0 var(--nb-ink);
}

.nb-card {
    background: #ffffff;
    border: var(--nb-border-width) solid var(--nb-ink);
    box-shadow: var(--nb-shadow-x) var(--nb-shadow-y) 0 var(--nb-ink);
    border-radius: 0;
    padding: 20px;
}

.nb-badge {
    display: inline-block;
    background: #ffffff;
    color: var(--nb-ink);
    border: var(--nb-border-width) solid var(--nb-ink);
    box-shadow: 4px 4px 0 var(--nb-ink);
    padding: 6px 10px;
    font-weight: 800;
}

/* buttons */
.nb-btn {
    display: inline-block;
    text-decoration: none;
    border: var(--nb-border-width) solid var(--nb-ink);
    padding: 14px 22px;
    font-weight: 800;
    color: #ffffff;
    background: var(--nb-primary);
    box-shadow: 6px 6px 0 var(--nb-ink);
}

.nb-btn:active { transform: translate(2px, 2px); box-shadow: 4px 4px 0 var(--nb-ink); }

.nb-btn--ghost {
    background: #ffffff;
    color: var(--nb-ink);
}

.nb-btn--whatsapp {
    background: var(--nb-whatsapp);
    color: #ffffff;
}

/* notice bar */
.nb-notice-bar {
    background: #ffffff;
    border-top: var(--nb-border-width) solid var(--nb-ink);
    border-bottom: var(--nb-border-width) solid var(--nb-ink);
}

.nb-notice-inner {
    display: flex;
    gap: 24px;
    align-items: center;
    justify-content: center;
    padding: 10px 0;
    font-weight: 700;
}

/* header */
.nb-header {
    background: #ffffff;
    border-bottom: var(--nb-border-width) solid var(--nb-ink);
}

.nb-nav {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 0;
}

.nb-nav ul { list-style: none; display: flex; gap: 20px; margin: 0; padding: 0; }
.nb-nav a { text-decoration: none; color: var(--nb-ink); font-weight: 800; padding: 6px 10px; border: 2px solid transparent; }
.nb-nav a:hover { border-color: var(--nb-ink); }

/* hero (keep gradient) */
.nb-hero {
    position: relative;
    color: #ffffff;
    background: linear-gradient(135deg, var(--nb-primary) 0%, var(--nb-accent) 100%);
    padding: 72px 0;
    overflow: hidden;
}

.nb-hero.has-photo { background-size: cover; background-position: center; }
.nb-hero .nb-hero-card { max-width: 820px; margin: 0 auto; text-align: center; }
.nb-hero h1 { font-size: 56px; line-height: 1.1; font-weight: 900; text-shadow: 3px 3px 0 rgba(0,0,0,0.35); }
.nb-hero p { font-size: 18px; margin: 14px 0 24px; }

/* category grid */
.nb-grid { display: grid; gap: 20px; }
.nb-grid.cols-4 { grid-template-columns: repeat(4, minmax(0, 1fr)); }
.nb-grid.cols-3 { grid-template-columns: repeat(3, minmax(0, 1fr)); }
.nb-grid.cols-2 { grid-template-columns: repeat(2, minmax(0, 1fr)); }

@media (max-width: 1024px) {
    .nb-grid.cols-4 { grid-template-columns: repeat(2, 1fr); }
    .nb-hero h1 { font-size: 40px; }
}

@media (max-width: 640px) {
    .nb-grid.cols-4, .nb-grid.cols-3 { grid-template-columns: 1fr; }
    .nb-hero { padding: 56px 0; }
    .nb-hero h1 { font-size: 32px; }
}

/* product card */
.nb-product-card img { width: 100%; height: 200px; object-fit: cover; border-bottom: var(--nb-border-width) solid var(--nb-ink); }
.nb-product-card .nb-product-meta { display: flex; align-items: center; justify-content: space-between; margin-top: 10px; }

/* trust strip */
.nb-strip { background: #ffffff; border-top: var(--nb-border-width) solid var(--nb-ink); border-bottom: var(--nb-border-width) solid var(--nb-ink); }
.nb-strip .nb-strip-inner { display: grid; grid-template-columns: repeat(4,1fr); gap: 20px; padding: 18px 0; }

@media (max-width: 768px) { .nb-strip .nb-strip-inner { grid-template-columns: repeat(2,1fr); } }

/* footer */
.nb-footer { background: #ffffff; border-top: var(--nb-border-width) solid var(--nb-ink); padding: 32px 0; }

